class Solution:
    def leastOpsExpressTarget(self, x: int, target: int) -> int:
        from collections import deque
        queue = deque([(0, 0)])
        visited = set([0])
        while queue:
            val, step = queue.popleft()
            if val == target:
                return step
            if val > target:
                continue
            for op in ['+', '-', '*', '/']:
                if op == '+':
                    new_val = val + x
                elif op == '-':
                    new_val = val - x
                elif op == '*':
                    new_val = val * x
                else:
                    if val == 0 or x == 0:
                        continue
                    new_val = val / x
                if new_val not in visited and new_val <= target:
                    queue.append((new_val, step + 1))
                    visited.add(new_val)
        return -1
